template.css:
/* Testimonial Rating Card */
.review-card {
  background: var(--card-bg, #ffffff);
  border-radius: var(--card-radius, 16px);
  padding: var(--card-padding, 28px);
  border: 1px solid var(--card-border, #e2e8f0);
  box-shadow: var(--card-shadow, 0 4px 20px rgba(0,0,0,0.06));
  display: flex;
  flex-direction: column;
  gap: 16px;
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}
.review-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 16px 40px rgba(0,0,0,0.10);
}

/* Stars */
.review-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.review-stars {
  position: relative;
  display: inline-block;
  font-size: 18px;
  line-height: 1;
}
.stars-bg {
  color: #e2e8f0;
  letter-spacing: 2px;
}
.stars-fill {
  position: absolute;
  left: 0;
  top: 0;
  overflow: hidden;
  color: #f59e0b;
  letter-spacing: 2px;
  white-space: nowrap;
}
.review-badge {
  font-size: 11px;
  font-weight: 600;
  color: #059669;
  background: #d1fae5;
  padding: 3px 10px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* Quote Body */
.review-body { margin: 0; }
.review-title {
  font-size: var(--title-font-size, 16px);
  font-weight: var(--title-font-weight, 600);
  color: var(--title-color, #0f172a);
  margin: 0 0 8px;
}
.review-text {
  font-size: var(--description-font-size, 15px);
  color: var(--description-color, #475569);
  line-height: var(--description-line-height, 1.7);
  margin: 0;
  font-style: italic;
}

/* Author */
.review-author {
  display: flex;
  align-items: center;
  gap: 12px;
  padding-top: 16px;
  border-top: 1px solid var(--card-border, #e2e8f0);
}
.review-avatar {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  object-fit: cover;
  border: 2px solid var(--card-border, #e2e8f0);
  flex-shrink: 0;
}
.review-author-info {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.review-name {
  font-size: var(--author-font-size, 15px);
  font-weight: var(--author-font-weight, 600);
  color: var(--author-color, #0f172a);
}
.review-role {
  font-size: var(--role-font-size, 13px);
  color: var(--role-color, #94a3b8);
}
.review-date {
  font-size: 12px;
  color: #94a3b8;
  white-space: nowrap;
}

/* Dark Mode */
.dark .review-card, [data-theme="dark"] .review-card {
  background: #1e293b;
  border-color: #334155;
  color: #e2e8f0;
}
.dark .review-title, [data-theme="dark"] .review-title { color: #f1f5f9; }
.dark .review-text, [data-theme="dark"] .review-text { color: #94a3b8; }
.dark .review-name, [data-theme="dark"] .review-name { color: #e2e8f0; }
.dark .review-author, [data-theme="dark"] .review-author { border-color: #334155; }

/* RTL */
[dir="rtl"] .review-author { flex-direction: row-reverse; }
[dir="rtl"] .review-author-info { text-align: right; }
[dir="rtl"] .review-header { flex-direction: row-reverse; }
[dir="rtl"] .stars-fill { left: auto; right: 0; }
[dir="rtl"] .review-title,
[dir="rtl"] .review-text { text-align: right; }
